INSERT INTO movie (title, original_title, type, region, release_date, duration, rating, rating_count, play_count, description, poster, video_url, is_vip, price, create_time, update_time) VALUES
('流浪地球3', 'The Wandering Earth 3', '科幻/冒险', '中国', '2026-02-10', 155, 8.7, 120000, 4500000, '太阳即将毁灭，人类带着地球踏上星际流浪之旅...', 'https://images.unsplash.com/photo-1446776653964-20c1d3a81b06?w=300&h=450&fit=crop', '/videos/wandering3.mp4', 1, 25.00, '2025-12-01 10:00:00', '2026-02-10 20:00:00'),
('满江红·前传', 'Full River Red: Prequel', '悬疑/喜剧', '中国', '2025-12-20', 148, 7.9, 98000, 3200000, '南宋绍兴年间，一群小人物与秦桧斗智斗勇的前传故事。', 'https://images.unsplash.com/photo-1518676590629-3dcbd9c5a5c9?w=300&h=450&fit=crop', '/videos/manjianghong.mp4', 1, 20.00, '2025-09-01 09:00:00', '2025-12-20 22:00:00'),
('封神第二部', 'Creation of the Gods II', '奇幻/战争', '中国', '2025-10-01', 160, 8.2, 210000, 6800000, '姜子牙与商王殷寿的终极对决，封神之战全面爆发。', 'https://images.unsplash.com/photo-1522708323590-d24dbb6b0267?w=300&h=450&fit=crop', '/videos/fengshen2.mp4', 1, 30.00, '2025-06-01 14:00:00', '2025-10-01 18:00:00'),
('热辣滚烫', 'YOLO', '喜剧/励志', '中国', '2024-02-10', 129, 7.8, 550000, 12000000, '一个宅女通过拳击找回自我的故事。', 'https://images.unsplash.com/photo-1571902943202-507ec2618e8f?w=300&h=450&fit=crop', '/videos/yolo.mp4', 0, 0.00, '2024-01-10 12:00:00', '2024-02-10 15:00:00'),
('奥本海默', 'Oppenheimer', '传记/历史', '美国', '2023-08-30', 180, 8.9, 890000, 8500000, '原子弹之父的传奇一生。', 'https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=300&h=450&fit=crop', '/videos/oppenheimer.mp4', 1, 25.00, '2023-07-20 11:00:00', '2023-08-30 09:00:00'),
('芭比', 'Barbie', '奇幻/喜剧', '美国', '2023-07-21', 114, 8.3, 420000, 6200000, '芭比乐园与真实世界的奇妙碰撞。', 'https://images.unsplash.com/photo-1529139574466-a303027c1d8b?w=300&h=450&fit=crop', '/videos/barbie.mp4', 0, 0.00, '2023-06-01 10:00:00', '2023-07-21 20:00:00'),
('飞驰人生2', 'Pegasus 2', '喜剧/运动', '中国', '2024-02-10', 121, 7.6, 320000, 7800000, '张驰重返赛场，挑战年轻车队。', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=300&h=450&fit=crop', '/videos/pegasus2.mp4', 0, 0.00, '2024-01-15 08:00:00', '2024-02-10 16:00:00'),
('哥斯拉大战金刚2', 'Godzilla x Kong: The New Empire', '动作/科幻', '美国', '2024-03-29', 115, 7.2, 280000, 5400000, '两大巨兽联手对抗新威胁。', 'https://images.unsplash.com/photo-1500964757637-c85e8a162699?w=300&h=450&fit=crop', '/videos/godzilla_kong.mp4', 1, 22.00, '2024-02-01 09:30:00', '2024-03-29 12:00:00'),
('第二十条', 'Article 20', '剧情/喜剧', '中国', '2024-02-10', 141, 7.5, 190000, 3500000, '检察官韩明处理一桩复杂案件，笑中带泪。', 'https://images.unsplash.com/photo-1563089145046-207db72f5907?w=300&h=450&fit=crop', '/videos/article20.mp4', 0, 0.00, '2024-01-20 10:00:00', '2024-02-10 18:00:00'),
('沙丘2', 'Dune: Part Two', '科幻/冒险', '美国', '2024-03-08', 166, 8.6, 510000, 7100000, '保罗·厄崔迪的复仇与崛起。', 'https://images.unsplash.com/photo-1419242902214-272b3f66ee7a?w=300&h=450&fit=crop', '/videos/dune2.mp4', 1, 28.00, '2024-02-01 14:00:00', '2024-03-08 21:00:00'),
('周处除三害', 'The Pig, the Snake, and the Pigeon', '动作/犯罪', '中国台湾', '2023-10-06', 134, 8.1, 98000, 1900000, '通缉犯陈桂林以为自己只剩半年生命，决心除掉排名前二的通缉犯。', 'https://images.unsplash.com/photo-1575936123452-b67c3203c357?w=300&h=450&fit=crop', '/videos/zhouchu.mp4', 1, 18.00, '2023-09-01 12:00:00', '2023-10-06 20:00:00'),
('年会不能停！', 'Johnny Keep Walking!', '喜剧', '中国', '2023-12-29', 117, 8.2, 210000, 4100000, '职场讽刺喜剧，戳中打工人心声。', 'https://images.unsplash.com/photo-1522708323590-d24dbb6b0267?w=300&h=450&fit=crop', '/videos/nianhui.mp4', 0, 0.00, '2023-11-15 10:00:00', '2023-12-29 19:00:00'),
('旺卡', 'Wonka', '歌舞/奇幻', '美国', '2023-12-08', 116, 8.0, 87000, 2300000, '威利·旺卡创办巧克力工厂前的奇妙冒险。', 'https://images.unsplash.com/photo-1504754524776-8f4f37790ca0?w=300&h=450&fit=crop', '/videos/wonka.mp4', 0, 0.00, '2023-10-20 09:00:00', '2023-12-08 14:00:00'),
('金手指', 'The Goldfinger', '犯罪/剧情', '中国香港', '2023-12-30', 125, 6.9, 54000, 1200000, '香港廉政公署追查一起惊天金融诈骗案。', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=300&h=450&fit=crop', '/videos/goldfinger.mp4', 1, 20.00, '2023-11-10 08:30:00', '2023-12-30 20:00:00'),
('孤注一掷', 'No More Bets', '犯罪/剧情', '中国', '2023-08-08', 130, 7.3, 320000, 8900000, '境外网络诈骗产业链内幕。', 'https://images.unsplash.com/photo-1571902943202-507ec2618e8f?w=300&h=450&fit=crop', '/videos/nomorebets.mp4', 0, 0.00, '2023-07-01 13:00:00', '2023-08-08 17:00:00'),
('我本是高山', 'Beyond the Clouds', '传记', '中国', '2023-11-24', 120, 7.0, 28000, 650000, '张桂梅校长的感人故事。', 'https://images.unsplash.com/photo-1470071459604-3b5ec3a7fe05?w=300&h=450&fit=crop', '/videos/gaoshan.mp4', 0, 0.00, '2023-10-10 11:00:00', '2023-11-24 18:00:00'),
('海王2', 'Aquaman and the Lost Kingdom', '动作/奇幻', '美国', '2023-12-20', 124, 6.8, 150000, 3500000, '海王与弟弟奥姆联手对抗黑蝠鲼。', 'https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=300&h=450&fit=crop', '/videos/aquaman2.mp4', 1, 22.00, '2023-11-01 15:00:00', '2023-12-20 21:00:00'),
('非诚勿扰3', 'If You Are the One 3', '喜剧/爱情', '中国', '2023-12-30', 119, 6.5, 42000, 890000, '笑笑和秦奋的十年之约。', 'https://images.unsplash.com/photo-1529139574466-a303027c1d8b?w=300&h=450&fit=crop', '/videos/feicheng3.mp4', 1, 18.00, '2023-11-20 09:00:00', '2023-12-30 20:00:00'),
('潜行', 'I Did It My Way', '动作/犯罪', '中国香港', '2024-01-11', 106, 6.7, 31000, 780000, '卧底警察与毒枭的生死较量。', 'https://images.unsplash.com/photo-1575936123452-b67c3203c357?w=300&h=450&fit=crop', '/videos/qianxing.mp4', 1, 20.00, '2023-12-01 14:30:00', '2024-01-11 19:00:00'),
('临时劫案', 'Rob N Roll', '喜剧/犯罪', '中国香港', '2024-01-19', 100, 7.1, 28000, 950000, '颓废中年兄弟意外卷入抢劫案。', 'https://images.unsplash.com/photo-1446776653964-20c1d3a81b06?w=300&h=450&fit=crop', '/videos/robnroll.mp4', 0, 0.00, '2023-12-15 10:00:00', '2024-01-19 20:00:00'),
('寄生虫', 'Parasite', '剧情/悬疑', '韩国', '2019-05-30', 132, 8.8, 450000, 9200000, '一家四口全是无业游民，直到长子通过伪造学历成为富豪家的家教。', 'https://images.unsplash.com/photo-1536440136628-849c177e76a1?w=300&h=450&fit=crop', '/videos/parasite.mp4', 1, 20.00, '2019-04-01 10:00:00', '2019-05-30 18:00:00'),
('釜山行', 'Train to Busan', '动作/恐怖', '韩国', '2016-07-20', 118, 8.5, 320000, 7800000, '一列前往釜山的列车上爆发丧尸危机。', 'https://images.unsplash.com/photo-1478720568477-152d9b164e26?w=300&h=450&fit=crop', '/videos/busan.mp4', 0, 0.00, '2016-06-01 09:00:00', '2016-07-20 20:00:00'),
('千与千寻', 'Spirited Away', '动画/奇幻', '日本', '2001-07-20', 125, 9.2, 680000, 15000000, '少女千寻误入神灵世界的奇幻冒险。', 'https://images.unsplash.com/photo-1559583985-c80d8ad9b29f?w=300&h=450&fit=crop', '/videos/spirited_away.mp4', 1, 18.00, '2001-06-01 10:00:00', '2001-07-20 15:00:00'),
('你的名字。', 'Your Name.', '动画/爱情', '日本', '2016-08-26', 106, 8.4, 410000, 11000000, '乡下少女与东京少年穿越时空的爱恋。', 'https://images.unsplash.com/photo-1518834107812-67b0b7c58434?w=300&h=450&fit=crop', '/videos/your_name.mp4', 0, 0.00, '2016-07-01 12:00:00', '2016-08-26 19:00:00');
